/bin/bash -lc 'tmp=$(mktemp); awk '"'
BEGIN{skip_oldfaq=0; removed_oldfaq=0; skip_dup_adv=0; seen_adv=0}
{
  line="'$0

  if (skip_dup_adv==1) {
    if (line ~ /''^## 快速参考卡$/) { skip_dup_adv=0; print line }
    next
  }

  if (removed_oldfaq==0 && line ~ /''^## 第五部分：常见问题$/) { skip_oldfaq=1; removed_oldfaq=1; next }
  if (skip_oldfaq==1) {
    if (line ~ /''^## 第六部分：训练工具推荐$/) { skip_oldfaq=0 } else { next }
  }

  if (line ~ /''^## 第六部分：训练工具推荐$/) line="## 第五部分：训练工具推荐"
  else if (line ~ /''^## 第七部分：常见问题$/) line="## 第六部分：常见问题"
  else if (line ~ /''^## 第八部分：步频训练进阶计划$/) { line="## 第七部分：步频训练进阶计划"; seen_adv=1 }
  else if (line ~ /''^## 第七部分：步频训练进阶计划$/) {
    if (seen_adv==1) { skip_dup_adv=1; next }
    else { seen_adv=1 }
  }

  print line
}
'"' docs/technique/06-cadence.md > \""'$tmp" && mv "$tmp" docs/technique/06-cadence.md'

